-- Get the first tenant company ID to assign to new users
SET @tenantId = (SELECT id FROM tenant_companies LIMIT 1);

-- Insert new Developer account
INSERT INTO users (
  openId, name, email, username, passwordHash, loginMethod,
  role, systemRole, tenantCompanyId, isActive, createdAt, updatedAt
) VALUES (
  UUID(), 'AXIOM Developer', 'dev@axiomcrm.com', 'axiomdev',
  '$2b$12$wu6H46df6ecPjjilh/DjB.fwVjrm4fyL2VJuBdDcmxR5Eb0h2YblO',
  'email', 'admin', 'developer', @tenantId, 1, NOW(), NOW()
);

-- Insert new CRM Admin account
INSERT INTO users (
  openId, name, email, username, passwordHash, loginMethod,
  role, systemRole, tenantCompanyId, isActive, createdAt, updatedAt
) VALUES (
  UUID(), 'AXIOM Admin', 'admin@axiomcrm.com', 'axiomadmin',
  '$2b$12$uUOixKH0sQWIx9pGfnwFB.8gtcW/FPLuBaRIFYRwBTfpdrzt4VJLm',
  'email', 'admin', 'user', @tenantId, 1, NOW(), NOW()
);

-- Verify both were created
SELECT id, name, email, username, role, systemRole FROM users WHERE email IN ('dev@axiomcrm.com', 'admin@axiomcrm.com');

